const express = require('express');
const redis = require('redis');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
require('dotenv').config();

const app = express();
const client = redis.createClient({
  url: process.env.REDIS_URL
});

app.use(express.json());
app.use(helmet());

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100
});

app.use(limiter);

client.on('error', (err) => {
  console.error('Redis client error', err);
});

app.get('/keys', async (req, res) => {
  const pattern = req.query.pattern;
  if (!pattern || !/^[a-zA-Z0-9:*]+$/.test(pattern)) {
    return res.status(400).send('Invalid pattern');
  }
  
  try {
    const keys = await client.keys(pattern);
    res.json(keys);
  } catch (err) {
    res.status(500).send('Server error');
  }
});

app.post('/admin', async (req, res) => {
  const { command, args } = req.body;
  const allowedCommands = ['FLUSHDB', 'FLUSHALL', 'INFO'];

  if (!allowedCommands.includes(command)) {
    return res.status(403).send('Forbidden command');
  }

  try {
    const result = await client.sendCommand(command, args || []);
    res.json(result);
  } catch (err) {
    res.status(500).send('Server error');
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});